SELECT *
FROM proxy_server_log


        AND server_id = #{serverId}


        AND filter_type LIKE CONCAT('%', #{filterType}, '%')


        AND process_status = #{processStatus}


        AND client_ip LIKE CONCAT('%', #{clientIp}, '%')


        AND access_time >= #{startTime}


        AND access_time <= #{endTime}


ORDER BY store_time DESC, id DESC

